{
    estimator <- if (robust) {
        function(vec) {
            h <- try(MASS::huber(vec), silent = TRUE)
            if (inherits(h, "try-error")) 
                median(vec)
            else h$mu
        }
    }
    else {
        "mean"
    }
    lev <- levels(y)
    if (identical("mean", estimator)) {
        list(conditionMeans = group_means(x, 1, y), levs = lev, 
            method = method, robust = robust)
    }
    else {
        list(conditionMeans = neuroim2::split_reduce(as.matrix(x), 
            y, estimator), levs = lev, method = method, robust = robust)
    }
}
